import React, { useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const s = {
  page: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #1a3a5c 0%, #2980b9 100%)' },
  card: { background: '#fff', borderRadius: 16, padding: '40px 36px', width: 380, boxShadow: '0 20px 60px rgba(0,0,0,0.3)' },
  logo: { textAlign: 'center', fontSize: 40, marginBottom: 8 },
  title: { textAlign: 'center', fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 4 },
  sub: { textAlign: 'center', fontSize: 13, color: '#888', marginBottom: 28 },
  label: { display: 'block', fontSize: 13, fontWeight: 600, color: '#444', marginBottom: 5 },
  input: { width: '100%', padding: '10px 14px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 15, outline: 'none', marginBottom: 16, transition: 'border 0.2s' },
  btn: { width: '100%', padding: '12px', background: '#1a3a5c', color: '#fff', border: 'none', borderRadius: 8, fontSize: 16, fontWeight: 700, cursor: 'pointer', marginTop: 4 },
  err: { background: '#fdecea', color: '#c0392b', padding: '10px 14px', borderRadius: 8, fontSize: 14, marginBottom: 16 },
  linkRow: { textAlign: 'center', marginTop: 20, fontSize: 14, color: '#666' }
};

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const { data } = await axios.post('/api/auth/login', form);
      login(data);
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    }
    setLoading(false);
  };

  return (
    <div style={s.page}>
      <div style={s.card}>
        <div style={s.logo}>🚌</div>
        <div style={s.title}>Bus Pass System</div>
        <div style={s.sub}>NIE Mysuru — Online Pass Management</div>
        {error && <div style={s.err}>{error}</div>}
        <form onSubmit={handleSubmit}>
          <label style={s.label}>Email</label>
          <input style={s.input} type="email" placeholder="your@email.com" value={form.email}
            onChange={e => setForm({ ...form, email: e.target.value })} required />
          <label style={s.label}>Password</label>
          <input style={s.input} type="password" placeholder="••••••••" value={form.password}
            onChange={e => setForm({ ...form, password: e.target.value })} required />
          <button style={s.btn} type="submit" disabled={loading}>{loading ? 'Logging in...' : 'Login'}</button>
        </form>
        <div style={s.linkRow}>
          Don't have an account? <Link to="/register" style={{ color: '#2980b9', fontWeight: 600 }}>Register</Link>
        </div>
        <div style={{ ...s.linkRow, marginTop: 10, fontSize: 12, color: '#aaa' }}>
          Admin: admin@buspass.com / admin123
        </div>
      </div>
    </div>
  );
}
